var MockJs = require('mockjs');                                                                                                 
                                                                                                                                
  (function () {                                                                                                                  
      // ==================== 1. 参数提取与校验 ====================                                                              
                                                                                                                                  
      var body = {};                                                                                                              
                                                                                                                                
      try {
          var bodyJson = $$.mockRequest.body.toJSON();

          if (bodyJson && bodyJson.raw) {
              body = JSON.parse(bodyJson.raw);
          } else {
              body = bodyJson || {};
          }
      } catch (e) {
          try {
              body = JSON.parse($$.mockRequest.body.toString());
          } catch (e2) {
              body = {};
          }
      }

      var siteCode = body.siteCode;
      var dateTime = body.dateTime;

      if (!siteCode || !dateTime) {
          $$.mockResponse.setBody({
              requestId: MockJs.Random.string('hex', 32),
              code: 400,
              msg: 'siteCode 和 dateTime 为必填参数',
              total: 0,
              rows: [],
              otherData: {}
          });
          $$.mockResponse.setCode(400);
          $$.mockResponse.setDelay(200);
          return;
      }

      // 可选参数与默认值
      var followUser = body.followUser || null;
      var pageNum = body.pageNum && body.pageNum > 0 ? body.pageNum : 1;
      var pageSize = body.pageSize ? (body.pageSize > 100 ? 100 : body.pageSize) : 10;

      // 根据 siteCode、dateTime、followUser 计算固定的 total
      var totalKey = siteCode + '|' + dateTime + '|' + (followUser || '');
      var total = totalKey.length % 5 === 0 ? 86 : 23;

      // 枚举映射表
      var carrierTypeMap = { 0: '提货', 1: '干线', 2: '配送', 3: '外包' };
      var carrierStatusMap = { 0: '待接单', 1: '待启运', 2: '运输中', 3: '已到达' };
      var followNumberMap = { 0: '0次', 1: '1次', 2: '2次', 3: '3次以上' };
      var finishTypeMap = { 0: '手动结束', 1: '规则结束' };
      var photoMap = { 0: '未打卡', 1: '已打卡' };
      var abnormalMap = { 0: '正常', 1: '异常' };
      var abnormalTypeList = ['其他', '离线', '滞留', '延误', '路线偏离'];

      // ==================== 2. 生成列表数据 ====================

      function generateItem(index) {
          var id = (pageNum - 1) * pageSize + index + 1;

          var carrierType = MockJs.Random.integer(0, 3);
          var carrierStatus = MockJs.Random.integer(0, 3);
          var followNumberType = MockJs.Random.integer(0, 3);
          var finishType = MockJs.Random.integer(0, 1);

          var loadingPhoto = carrierStatus === 3 ? 1 : MockJs.Random.integer(0, 1);
          var unloadingPhoto = carrierStatus === 3 ? 1 : MockJs.Random.integer(0, 1);

          var latestAbnormalFlag = MockJs.Random.integer(0, 1);
          var latestAbnormalType = null;

          if (latestAbnormalFlag === 1) {
              var count = MockJs.Random.integer(1, 3);
              var shuffled = MockJs.Random.shuffle(abnormalTypeList.slice());
              latestAbnormalType = shuffled.slice(0, count).join('、');
          }

          return {
              id: id,
              carrierOrderNo: MockJs.Random.string('ABCDEFGHIJKLMNOPQRSTUVWXYZ0123456789', 12, 16),
              settlementCusNames: MockJs.Random.cname(),
              carrierType: carrierType,
              carrierTypeDesc: carrierTypeMap[carrierType],
              carrierStatus: carrierStatus,
              carrierStatusDesc: carrierStatusMap[carrierStatus],
              followUser: followUser || MockJs.Random.string('lower', 6, 10),
              followUserName: MockJs.Random.cname(),
              driverName: MockJs.Random.cname(),
              driverMobile: '13800138000',
              carNo: '京A' + MockJs.Random.string('0123456789', 5),
              followNumberType: followNumberType,
              followNumberDesc: followNumberMap[followNumberType],
              finishType: finishType,
              finishTypeDesc: finishTypeMap[finishType],
              shiperArriveAddr: MockJs.Random.pick(['北京-上海', '广州-深圳', '成都-重庆', '杭州-南京', '武汉-郑州']),
              loadingPhoto: loadingPhoto,
              unloadingPhoto: unloadingPhoto,
              loadingPhotoStatus: photoMap[loadingPhoto],
              unloadingPhotoStatus: photoMap[unloadingPhoto],
              latestAbnormalFlag: latestAbnormalFlag,
              latestAbnormalStatus: abnormalMap[latestAbnormalFlag],
              latestAbnormalType: latestAbnormalType
          };
      }

      var rows = [];
      var validPageSize = pageNum * pageSize > total ? total - (pageNum - 1) * pageSize : pageSize;

      if (validPageSize < 0) {
          validPageSize = 0;
      }

      for (var i = 0; i < validPageSize; i++) {
          rows.push(generateItem(i));
      }

      // ==================== 3. 组装响应 ====================

      var response = {
          requestId: MockJs.Random.string('hex', 32),
          total: total,
          rows: rows,
          code: 200,
          msg: 'success',
          otherData: {}
      };

      $$.mockResponse.setBody(response);
      $$.mockResponse.setCode(200);
      $$.mockResponse.setDelay(200);
  })();

